import type { VaultInitResult, VaultRecord } from "./types.js";
import type { VaultRepositories } from "../backend/vault-runtime/db/repositories.js";

let currentVault: VaultRecord | null = null;
let vaultInitResult: VaultInitResult | null = null;

export function getCurrentVault() {
  return currentVault;
}

export function requireCurrentVault() {
  if (!currentVault) {
    throw new Error("No hay vault cargado.");
  }

  return currentVault;
}

export function setCurrentVault(vault: VaultRecord | null) {
  currentVault = vault;
}

export function updateCurrentVault(updates: Partial<VaultRecord>) {
  if (!currentVault) {
    throw new Error("No hay vault cargado para actualizar.");
  }

  currentVault = {
    ...currentVault,
    ...updates,
  };

  return currentVault;
}

export function getCurrentVaultDb() {
  return currentVault?.db ?? null;
}

export function requireCurrentVaultDb() {
  const db = getCurrentVaultDb();

  if (!db) {
    throw new Error("La DB del vault todavia no esta inicializada.");
  }

  return db;
}

export function getCurrentVaultRepositories() {
  return currentVault?.repositories ?? null;
}

export function requireCurrentVaultRepositories(): VaultRepositories {
  const repositories = getCurrentVaultRepositories();

  if (!repositories) {
    throw new Error("Los repositorios del vault todavia no estan inicializados.");
  }

  return repositories;
}

export function getVaultInitResult() {
  return vaultInitResult;
}

export function setVaultInitResult(result: VaultInitResult | null) {
  vaultInitResult = result;
}
